async (params, browser) => {
  // Open page
  await browser.open('https://letterboxd.com/films/popular/')

  // Wait for content
  await browser.waitForSelector('ul.poster-list, li.poster-container', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const films = Array.from(document.querySelectorAll('li.poster-container')).slice(0,30).map((el,i) => { const img = el.querySelector('img'); const poster = el.querySelector('div.film-poster'); const slug = poster?poster.getAttribute('data-film-slug'):''; return { rank: i+1, title: img?img.getAttribute('alt'):'', url: slug?'https://letterboxd.com/film/'+slug+'/':'' }; }).filter(f=>f.title); return { films, url: window.location.href }`)

  return page_data
}
